-- PAGO (Poblacion automática y aleatoria)
select 
    monto, 
    -- metodo de pago al azar del array
    (array['Efectivo', 'Transferencia', 'Bitcoin', 'Tarjeta'])[floor(random() * 4 + 1)::int], 
    num_factura 
from Factura 
where monto > 0;
